const y = require\('js-yaml'\);
const fs = require\('fs'\);
const doc = y.load\(fs.readFileSync\('/home/runner/workspace/openapi.yaml','utf8'\)\);
let opCount = 0;
for \(const [path, methods] of Object.entries\(doc.paths\)\) {
  for \(const [method, op] of Object.entries\(methods\)\) {
    if \(['get','post','put','delete','patch'].includes\(method\)\) {
      opCount++;
    }
  }
}
console.log\('Total operations:', opCount\);
console.log\('OpenAPI version:', doc.openapi\);
console.log\('Info title:', doc.info.title\);
console.log\('Info version:', doc.info.version\);
console.log\('Server URL:', doc.servers[0].url\);
console.log\('Tags:', doc.tags.map\(t => t.name\).join\(', '\)\);
")

Bash(node -e '
const fs = require\("fs"\);
const routeLines = fs.readFileSync\("/home/runner/workspace/server/routes.ts", "utf8"\);
const serverRoutes = new Set\(\);
const regex = /\(?:app|router\)\\.\(get|post|put|delete|patch\)\\\("\\/api\(\\/[^"]+\)"/g;
let m;
while \(\(m = regex.exec\(routeLines\)\) !== null\) {
  const method = m[1];
  let path = m[2].replace\(/:\(\\w+\)/g, "{$1}"\);
  serverRoutes.add\(method + " " + path\);
}
const specLines = fs.readFileSync\("/home/runner/workspace/openapi.yaml", "utf8"\).split\("\\n"\);
const specRoutes = new Set\(\);
let currentPath = null;
for \(const line of specLines\) {
  const pathMatch = line.match\(/^  \(\\/[^ :]+\):/\);
  const methodMatch = line.match\(/^    \(get|post|put|delete|patch\):/\);
  if \(pathMatch\) currentPath = pathMatch[1];
  if \(methodMatch && currentPath\) specRoutes.add\(methodMatch[1] + " " + currentPath\);
}
const missing = [...serverRoutes].filter\(r => !specRoutes.has\(r\)\).sort\(\);
console.log\("Server: " + serverRoutes.size + ", Spec: " + specRoutes.size + ", Missing: " + missing.length\);
missing.forEach\(r => console.log\("  " + r\)\);
')
